const Q_CHEMISTRY_2021_MODEL_I=[{"id": "objective>Chemistry>2021-Model-I>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following types of hybridization is found in tetrahedral molecules?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sp</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sp<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sp<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sp<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>d</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The type of hybridization found in tetrahedral molecules is sp<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> hybridization. Tetrahedral molecules include alkanes and their derivative.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : SHAPES OF SIMPLE MOLECULES"}, {"id": "objective>Chemistry>2021-Model-I>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Detergents are much better than soap for laundry because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">detergents are synthetic while soaps are not</div>", "<div style=\"font-family:Cambria;font-size:17px;\">detergents are more soluble in water than soaps</div>", "<div style=\"font-family:Cambria;font-size:17px;\">scum is precipitated when soaps are used with hard water but not with detergents </div>", "<div style=\"font-family:Cambria;font-size:17px;\">soaps are in bars while detergents are in powdered form</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Detergents are better than soaps in laundry because soaps do not lather readily in hard water; whereas, detergents lather readily in hard water. <br/> N.B: Soaps do not lather in hard water because of the precipitation of insoluble scum when soaps are used with hard water.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOATES"}, {"id": "objective>Chemistry>2021-Model-I>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Octane number is highest in petrol containing a high proportion of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Octane </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2-methylpentane </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2, 4-dimethylpentane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2, 2, 4-trimethylpentane </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Octane number is highest in petrol containing a high proportion of a highly branched isomer of octane → 2, 3, 4 - trimethyl pentane. <br/> </div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2021-Model-I>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The compound given above is  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1, 1 - dimethyl, 1-ethyl prop- 1 - ene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2, 3, 4 - trimethyl but-2-ene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 - methyl, 3 - etyl but - 2 - ene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2, 3 - dimethyl pent - 2 - ene</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2021-Model-I/utmechm2021m1q4s.png\" style=\"position:relative;max-width:100%;\"/> <br/> - The longest continuous carbon chain contains five (5) carbon atoms and a double bond on the second carbon, hence, the root name of the compound given is pent-2-ene. <br/>  <br/> - There are two(2) methyl groups on the 2nd and 3rd carbons. <br/> ∴ The compound given is - <br/> 2, 3 - dimethylpent-2-ene  </div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2021-Model-I>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not true about glucose and fructose? They </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">are structural isomers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce Fehling's solution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">can be obtained by the hydrolysis of starch</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are readily fermented by enzymes </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Glucose can be fermented by enzymes, but not fructose. <br/> Glucose → Ethanol + CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> (Fermentation) [in the presence of Enzyme] <br/> N.B: Enzyme ≡ Zymase <br/> Fructose → No reaction. (in the presence of zymase) <br/> </div>", "topic": "ORGANIC COMPOUNDS : CARBOHYDRATES"}, {"id": "objective>Chemistry>2021-Model-I>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Why is potassium fluoride added to the electrolyte in the extraction of sodium from fused sodium chloride?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Pure sodium chloride does not conduct electricity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Potassium fluoride prevents the sodium produced from attacking the electrodes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Potassium fluoride increases conductivity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Potassium fluoride reduces the temperature at which sodium chloride fuses</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Potassium fluoride reduces the temperature at which sodium chloride fuses.</div>", "topic": "ELECTROLYSIS : ELECTROCHEMICAL CELLS"}, {"id": "objective>Chemistry>2021-Model-I>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is extensively used in manufacturing photographic chemicals?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Aluminium chloride </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Zinc chloride</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Silver chloride</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mercury (II) chloride</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Silver chloride is extensively used in manufacturing photographic chemicals. When exposed to light, silver chloride decomposes to form silver, which is used in the photographic development process. The silver forms the dark areas in a photographic image.</div>", "topic": "METALS AND THEIR COMPOUNDS : COPPER"}, {"id": "objective>Chemistry>2021-Model-I>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When an element can exist in two or more forms in the same physical state, the element is said to exhibit.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">isotopy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">allotropy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">isomerism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hygroscopy</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Allotropy is the existence of an element in two or more forms in the same physical state. Elements that exhibit allotropy include: sulphur, carbon, oxygen e.t.c.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE CONCEPT OF ATOMS, MOLECULES AND IONS"}, {"id": "objective>Chemistry>2021-Model-I>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following reactions represents the laboratory preparation of hydrogen?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span> → CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span> → 2NaOH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Zn<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + 2HCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → ZnCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(aq)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cu<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span> → CuO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The laboratory preparation of hydrogen gas usually involves the action of dilute HCl or H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> on zinc granules.  <br/> Zn +2HCl → ZnCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "topic": "NON-METALS AND THEIR COMPOUNDS : HYDROGEN"}, {"id": "objective>Chemistry>2021-Model-I>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major raw material in plastic industry is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ethene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sulphur</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethanol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethane </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The major raw material in the plastic industry is ethene. Ethene is a hydrocarbon that is widely used in the chemical industry, and its polymers are used to create various types of plastic. Ethanol, sulphur, and ethane are not the major raw materials in the plastic industry.</div>", "topic": "ORGANIC COMPOUNDS : GIANT MOLECULES"}, {"id": "objective>Chemistry>2021-Model-I>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The earthly impurities in iron ore are removed in the Blast Furnace by the reaction</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + C → 2CO</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fe<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> + 3CO → 2Fe + 3CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">SiO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + CaO → CaSiO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> → CaO + CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The earthly impurities in iron ore are removed in the Blast Furnace by the reaction SiO2 + CaO → CaSiO3. This reaction describes the formation of slag in the blast furnace, which helps to remove impurities from the iron ore. The other reactions do not describe the removal of impurities from iron ore.</div>", "topic": "METALS AND THEIR COMPOUNDS : IRON"}, {"id": "objective>Chemistry>2021-Model-I>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following elements can form more than one acidic oxide?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Hydrogen </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sulphur </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Carbon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Aluminium</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sulphur can form more than one acidic oxide. It can form SO2 and SO3, both of which are acidic oxides. Hydrogen forms water with oxygen, which is neutral. Carbon forms CO and CO2, both of which are neutral or weakly acidic. Aluminium forms Al2O3, which is amphoteric (can act as both an acid and a base).</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : OXYGEN AND SULPHUR"}, {"id": "objective>Chemistry>2021-Model-I>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Brass is an alloy of copper and </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">iron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chromium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">zinc</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tin</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Brass is an alloy made primarily of copper and zinc. An alloy is a mixture of two or more elements, at least one of which is a metal. In the case of brass, copper provides the strength and zinc gives the alloy its distinctive yellow color.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALLOY"}, {"id": "objective>Chemistry>2021-Model-I>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following equations does not illustrate correctly one of the reactions of carbon(IV)oxide?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + 2NaOH → Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2Mg + CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → 2MgO + C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + Ca(OH)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → HCOOH</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → HCOOH does not illustrate correctly one of the reactions of carbon(IV)oxide</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : CARBON"}, {"id": "objective>Chemistry>2021-Model-I>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How many orbitals are in the d-subshell?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The d-subshell contains 5 orbitals. In quantum mechanics, an orbital is a mathematical function that describes the wave-like behavior of an electron in an atom. The d-subshell is the third subshell and can hold up to 10 electrons.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2021-Model-I>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An element X has isotopic masses of 6 and 7. If the relative abundance is 3 to 2 respectively, what is the relative atomic mass of X?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.9</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Recall: R.A.M = M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>α<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> + M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>α<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R.A.M</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6</td><td style=\"text-align:center;\">(</td><td style=\"text-align:center;\">3<hr size=\"1\" />5</td><td style=\"text-align:center;\">)</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">7</td><td style=\"text-align:center;\">(</td><td style=\"text-align:center;\">2<hr size=\"1\" />5</td><td style=\"text-align:center;\">)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">18<hr size=\"1\" />5</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">14<hr size=\"1\" />5</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3.6</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">2.8</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6.4</td><td style=\"text-align:center;\">g/mol</td></tr></table></div> <br/> </div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2021-Model-I>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following compounds would react rapidly with bromine?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Benzene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hexane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hexene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hexanol</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The addition of bromine to most alkenes is so fast that when bromine is added dropwise to a solution of the alkene the red bromine color disappears almost immediately. In fact, this discharge of color is a useful qualitative test for alkenes.</div>", "topic": "NUCLEAR CHEMISTRY : NUCLEAR REACTIONS"}, {"id": "objective>Chemistry>2021-Model-I>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The type of chemical bonding involved in the formation of NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> from a molecule of ammonia and a proton is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">covalent bonding </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dative bonding </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ionic bonding </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Metallic bonding </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The type of chemical bonding involved in the formation of ammonium ion (NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>) from ammonia and proton is Dative Bonding. Dative Bonding involves the donation of the shared pair of electrons by one of the participating atoms. <br/>  <img src=\"2021-Model-I/chem8.png\" style=\"position:relative;max-width:100%;\"/></div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2021-Model-I>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The oxidation number of iodine in the iodate ion (IO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span>) is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">-5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">-1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">+1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">+5</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The oxidation number of iodine in the iodate ion (IO3-) is +5. This is because oxygen has an oxidation number of -2 and there are three oxygen atoms, making a total of -6. The overall charge of the ion is -1, so iodine must have an oxidation number of +5 to balance this out.</div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>2021-Model-I>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Consider the reaction: 2Al<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + 6H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>) → 2Al<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span> + 3H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>. What is the total number of electrons transferred from aluminium atoms to hydrogen ions?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> 2Al + 6H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> → 2Al<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span> + 3H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> Aluminium transfers six(6) electrons to 6H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> for it to become neutral (3H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>).</div>", "topic": "OXIDATION AND REDUCTION : REDUCTION"}, {"id": "objective>Chemistry>2021-Model-I>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Use the table above to answer the question. <br/>  <br/> Which of the letters indicate elements which exist as diatomic gases? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">B and G</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C and F</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C and A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A and F</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hydrogen (A) and Group 7 elements exist as diatomic gases.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE PERIODIC TABLE AND PERIODICITY OF ELEMENTS"}, {"id": "objective>Chemistry>2021-Model-I>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Use the table above to answer the question. <br/> Which of the letters represents an alkaline earth metal?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">F</div>", "<div style=\"font-family:Cambria;font-size:17px;\">E</div>", "<div style=\"font-family:Cambria;font-size:17px;\">D</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Alkaline earth metals are group 2 elements. C is a group 2 element.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALKALINE-EARTH METALS"}, {"id": "objective>Chemistry>2021-Model-I>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements about the standard hydrogen electrode is not correct?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The hydrogen gas is at a pressure of 1 atmosphere</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A solution containing 1 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3 </span> of H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> (aq) ions is used</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A platinum electrode is used</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The temperature is kept at 20 °C</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The standard hydrogen electrode is a reference electrode used in electrochemical measurements. The conditions for the standard hydrogen electrode are: the hydrogen gas is at a pressure of 1 atmosphere, a solution containing 1 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> of H+(aq) ions is used, a platinum electrode is used, and the temperature is kept at 25 °C (298 K), not 20 °C. </div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2021-Model-I>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Electrolytes is applied in the following processes except </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">electroplating </div>", "<div style=\"font-family:Cambria;font-size:17px;\">extraction of aluminium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">extraction of iron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">purification of copper</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Electrolytes are not used in the extraction of iron. The extraction of iron is done through the process of reduction in a blast furnace, not electrolysis. Therefore, electrolytes are not applied in this process.</div>", "topic": "ELECTROLYSIS : ELECTROLYTES AND NON-ELECTROLYTES"}, {"id": "objective>Chemistry>2021-Model-I>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The activation energy of a reaction can be altered by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">adding a reducing agent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">applying a high pressure </div>", "<div style=\"font-family:Cambria;font-size:17px;\">using a catalyst</div>", "<div style=\"font-family:Cambria;font-size:17px;\">changing the temperature </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The activation energy of a reaction can be altered by using a catalyst. A catalyst works by providing an alternative reaction pathway with a lower activation energy. This allows the reaction to proceed at a faster rate.</div>", "topic": "RATE OF CHEMICAL REACTION : ACTIVATION ENERGY"}, {"id": "objective>Chemistry>2021-Model-I>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What volume of hydrogen gas at s.t.p will be produced when 48g of magnesium reacts completely with dilute hydrochloric acid?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">11.2dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">22.4dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">33.6dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">44.8dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Equation of Reaction: <br/> Mg + 2HCl → MgCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> From the reaction above, <br/> 24g of Magnesium produce 1 mole of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> 24g Mg → 22.4dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> 48g Mg → x <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">24<hr size=\"1\" />48</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">22.4<hr size=\"1\" />x</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">22.4<hr size=\"1\" />x</td></tr></table></div> <br/> x = 44.8dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> </div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>2021-Model-I>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A solution of sodium hydroxide containing 0.6g in 250cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of solution has a concentration of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.04 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.06 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.96 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.15 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> mass(m) = 0.6g <br/> volume (v) = 250cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> = 0.25dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> Molar mass of NaOH=23+16+1=40 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">mass</td><td style=\"text-align:center;\">concentration</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.6<hr size=\"1\" />0.25</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2.4g/dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:</td><td style=\"text-align:center;\">Molar</td><td style=\"text-align:center;\">concentration</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">mass concentration<hr size=\"1\" />molar mass</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">∴</td><td style=\"text-align:center;\">molar</td><td style=\"text-align:center;\">concentration</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2.4<hr size=\"1\" />40</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.06</td><td style=\"text-align:center;\">moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></td></tr></table></div></div>", "topic": "ACID BASE AND SALTS : ACID AND BASE TITRATIONS"}, {"id": "objective>Chemistry>2021-Model-I>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is suitable for producing insoluble salts?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Thermal decomposition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oxidation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Neutralization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Double decomposition</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Insoluble salts are typically produced through a double decomposition reaction. In this type of reaction, two compounds react, and the positive ions (cations) and the negative ions (anions) from the original compounds switch places, forming two new compounds. One of these new compounds is typically insoluble in water and precipitates out of the solution, forming a solid. This is the insoluble salt.</div>", "topic": "ACID BASE AND SALTS : QUALITATIVE COMPARISON"}, {"id": "objective>Chemistry>2021-Model-I>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Pig-iron is brittle because it contains </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a high percentage of carbon as impurity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">calcium triosilicate (IV)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">unreacted haemetite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">undecomposed limestone </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pig iron is brittle because it contains a high percentage of carbon as an impurity. The carbon forms a hard but brittle crystalline structure with the iron, which makes the pig iron hard but also brittle. This is why pig iron is typically further refined to reduce the carbon content and improve its mechanical properties.</div>", "topic": "METALS AND THEIR COMPOUNDS : IRON"}, {"id": "objective>Chemistry>2021-Model-I>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following will affect the rate of formation of S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> in the reaction represented by the equation below? <br/> S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span> + S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Increase in temperature </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Increase in pressure </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Removal of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Use of catalyst </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The rate of formation of S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> will be affected by the removal of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O. The removal of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O will favour the forward reaction, hence, more of S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> will be formed.</div>", "topic": "RATE OF CHEMICAL REACTION : FACTORS"}, {"id": "objective>Chemistry>2021-Model-I>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Greenhouse effect can be reduced by controlling</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">water evaporation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">burning of wood and fossil fuel </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the use of aerosols</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the use of artificial fertilizers </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Greenhouse effect can be reduced by controlling the release of carbon through burning of wood and fossil fuels.</div>", "topic": "ENVIRONMENTAL POLLUTION : AIR POLLUTION"}, {"id": "objective>Chemistry>2021-Model-I>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following oxides is amphoteric?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Carbon(II) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nitrogen(IV) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lead(II) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Calcium oxide</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Aluminium oxide is an amphoteric oxide. With sodium hydroxide solution, it produces water and sodium aluminate (NaAlO2). The other common examples of amphoteric oxides include SnO, ZnO, and PbO. Al2O3 is an amphoteric oxide.</div>", "topic": "ENVIRONMENTAL POLLUTION : SOIL POLLUTION"}, {"id": "objective>Chemistry>2021-Model-I>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements is not a postulate of the kinetic theory of gases?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">molecules move with the same speed </div>", "<div style=\"font-family:Cambria;font-size:17px;\">intermolecular forces are negligible </div>", "<div style=\"font-family:Cambria;font-size:17px;\">molecules are in a constant random motion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">collision between molecules is elastic</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The kinetic theory of gases does not postulate that all molecules move with the same speed. Instead, it states that the speed of gas molecules varies, with some moving faster and others slower.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : AN OUTLINE OF THE KINETIC THEORY OF MATTER"}, {"id": "objective>Chemistry>2021-Model-I>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the quantity of electricity passed when 0.4A flows for 1 hour 20 minutes through an electrolytic cell.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4800C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3840C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1920C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">32C</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Current, I = 0.4A <br/> Time, t = 1 hour 20 minutes = 80 minutes = 4800s <br/> Q = ? <br/> Recall: Q = It <br/> Q = 0.4 x 4800 = 1920C</div>", "topic": "ELECTROLYSIS : FARADAY'S LAW OF ELECTROLYSIS"}, {"id": "objective>Chemistry>2021-Model-I>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When 100cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of a saturated solution of kClO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> at 40°C is evaporated, 14g of salt is recovered. What is the solubility of kClO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> at 40°C? <br/> [kClO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> = 122.5]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">11.42 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.80 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.14 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.88 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> mass, m = 14g <br/> volume, v = 100cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> = 0.1dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">∴</td><td style=\"text-align:center;\">Solubility</td><td style=\"text-align:center;\">in</td><td style=\"text-align:center;\">gdm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">14<hr size=\"1\" />0.1</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">140gdm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></td></tr></table></div> <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Solubility</td><td style=\"text-align:center;\">in</td><td style=\"text-align:center;\">moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">solubility in dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span><hr size=\"1\" />molar mass</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">140<hr size=\"1\" />122.5</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1.14 mol/dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></td></tr></table></div></div>", "topic": "SOLUBILITY : UNSATURATED SATURATED AND SUPERSATURATED SOLUTIONS"}, {"id": "objective>Chemistry>2021-Model-I>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following scientists discovered the neutron?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ernest Rutherford </div>", "<div style=\"font-family:Cambria;font-size:17px;\">J.J Thompson</div>", "<div style=\"font-family:Cambria;font-size:17px;\">James Chadwick</div>", "<div style=\"font-family:Cambria;font-size:17px;\">R. A Milikan</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The neutron was discovered by James Chadwick in 1932. He performed an experiment where he bombarded a thin sheet of beryllium with alpha particles and observed that neutral particles with a mass approximately equal to that of protons were emitted. He named these particles 'neutrons'.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2021-Model-I>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The following properties are characteristics of transition elements except </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">formation of complex ions </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fixed oxidation states </div>", "<div style=\"font-family:Cambria;font-size:17px;\">formation of coloured compounds </div>", "<div style=\"font-family:Cambria;font-size:17px;\">catalytic abilities </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Transition elements are known for their variable oxidation states, not fixed oxidation states. This is due to the fact that their valence electrons are in two different sets of orbitals (4s and 3d), and they can lose different numbers of electrons from these orbitals, leading to different oxidation states.</div>", "topic": "METALS AND THEIR COMPOUNDS : METALS OF THE FIRST TRANSITION SERIES"}, {"id": "objective>Chemistry>2021-Model-I>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> was dissolved in water, the container was cold to touch. This implies that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the process is endothermic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the process is exothermic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>Cl is highly soluble in water </div>", "<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>Cl forms a saturated solution</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This is an indication that the reaction absorbs heat from the surroundings; that is why the container (surroundings) is cold to touch. Therefore, the reaction is endothermic.</div>", "topic": "ENERGY CHANGES : ENDOTHERMIC AND EXOTHERMIC REACTIONS"}, {"id": "objective>Chemistry>2021-Model-I>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following separation techniques would show that black ink is a mixture of chemical compounds?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">crystallization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chromatography</div>", "<div style=\"font-family:Cambria;font-size:17px;\">filtration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sublimation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Chromatography is a separation technique that can be used to separate the different components of a mixture and thus demonstrate that a substance (like black ink) is a mixture of different compounds. It works by passing the mixture through a medium where the different components move at different rates, allowing them to be separated.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>2021-Model-I>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Consider the following energy profile diagram of the endothermic reaction <br/> A + B → C + D <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The enthalpy change is  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">80 kJ/mol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60 kJ/mol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">120 kJ/mol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">40 kJ/mol</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: A + B → C + D <br/> ΔH = H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">P</span> - H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">R</span> <br/> H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">P</span> = 80KJ/mol <br/> H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">R</span> = 20KJ/mol <br/> ∴ ΔH = 80 - 20 = 60 kJ/mol</div>", "topic": "ENERGY CHANGES : ENDOTHERMIC AND EXOTHERMIC REACTIONS"}];
